    'more'    => "MORE(1)                   User Commands                  MORE(1)\n\nNAME\n       more - file perusal filter for crt viewing\n\nSYNOPSIS\n       more [options] file...\n\nDESCRIPTION\n       more is a filter for paging through text one screenful at a time.\n\n       -d     Prompt with '[Press space to continue, q to quit.]'\n\n       -p     Do not scroll. Instead, clear the whole screen and then\n              display the text.\n\n       +num   Start at line number num.\n\nINTERACTIVE COMMANDS\n       SPACE        display next k lines of text (default current screen size)\n       ENTER        display next k lines of text (default 1)\n       q or Q       exit more\n       /pattern     search for pattern in remaining text\n       =            display current line number\n       h or ?       display this help text\n\nAUTHOR\n       Written by Eric Shienbrood, Geoff Peck, John Foderaro.\n\nutil-linux                       March 2026                        MORE(1)",

    'less'    => "LESS(1)                   User Commands                  LESS(1)\n\nNAME\n       less - opposite of more\n\nSYNOPSIS\n       less [-[+]aABcCdeEfFgGiIJKLmMnNqQrRsSuUVwWX~]\n            [-b space] [-h lines] [-j line] [-k keyfile]\n            [-o logfile] [-p pattern] [-P prompt] [-t tag]\n            [-T tagsfile] [-x tab,...] [-y lines] [-[z] lines]\n            [+[+]cmd] [--] [filename]...\n\nDESCRIPTION\n       less is a program similar to more, but which allows backward\n       movement in the file as well as forward movement.\n\nINTERACTIVE COMMANDS\n       SPACE or f    Scroll forward one window\n       b             Scroll backward one window\n       ENTER or e    Scroll forward one line\n       y             Scroll backward one line\n       g             Go to first line\n       G             Go to last line\n       /pattern      Search forward for pattern\n       ?pattern      Search backward for pattern\n       n             Repeat previous search\n       q or Q        Exit less\n       h             Display this help\n\n       less is more feature-rich than more: it supports both forward\n       and backward navigation, search highlighting, and does not need\n       to read the entire file before displaying.\n\nAUTHOR\n       Written by Mark Nudelman.\n\nless                             March 2026                        LESS(1)",

    'cron'    => "CRON(8)               System Manager's Manual              CRON(8)\n\nNAME\n       cron - daemon to execute scheduled commands\n\nSYNOPSIS\n       cron [-n] [-p] [-s] [-m <mailcommand>]\n\nDESCRIPTION\n       cron is started automatically from /etc/init.d on entering\n       multi-user runlevels.  It searches /var/spool/cron for crontab\n       files which are named after accounts in /etc/passwd; the found\n       crontabs are loaded into the memory.\n\n       cron also searches for /etc/anacrontab and any files in the\n       /etc/cron.d directory.  These differ from user crontabs in that\n       they contain a username field in the entry.\n\nCRONTAB FORMAT\n       A crontab entry has the form:\n\n       minute  hour  day  month  weekday  command\n\n       Ranges, lists, and steps are allowed:\n         */5 * * * *    every 5 minutes\n         0 2 * * *      daily at 02:00\n         0 9 * * 1      every Monday at 09:00\n\nFILES\n       /etc/crontab          system crontab\n       /etc/cron.d/          additional crontab fragments\n       /etc/cron.hourly/     scripts run every hour\n       /etc/cron.daily/      scripts run every day\n       /etc/cron.weekly/     scripts run every week\n       /etc/cron.monthly/    scripts run every month\n       /var/spool/cron/      per-user crontabs\n\nSEE ALSO\n       crontab(1), anacron(8)\n\nPaul Vixie                       March 2026                        CRON(8)",

    'crontab' => "CRONTAB(1)                User Commands               CRONTAB(1)\n\nNAME\n       crontab - maintain crontab files for individual users\n\nSYNOPSIS\n       crontab [-u user] file\n       crontab [-u user] [-l | -r | -e] [-i]\n\nDESCRIPTION\n       crontab is the program used to install, remove or list the tables\n       used to drive the cron daemon.\n\n       -l     List the current crontab.\n\n       -e     Edit the current crontab using the editor specified by the\n              VISUAL or EDITOR environment variable.\n\n       -r     Remove the current crontab.\n\n       -u user\n              Specify the name of the user whose crontab is to be\n              modified.  If this option is not given, it defaults to\n              the current user.\n\nFILES\n       /var/spool/cron/crontabs/    user crontab storage\n\nSEE ALSO\n       cron(8)\n\nPaul Vixie                       March 2026                     CRONTAB(1)",

    'httpd'   => "HTTPD(8)              System Manager's Manual             HTTPD(8)\n\nNAME\n       httpd - Apache Hypertext Transfer Protocol Server\n\nSYNOPSIS\n       httpd [-d serverroot] [-f config] [-C directive] [-c directive]\n             [-D parameter] [-e level] [-E file] [-k signal]\n             [-T] [-t] [-S] [-X] [-v] [-V] [-h] [-l] [-L] [-M] [-n name]\n\nDESCRIPTION\n       httpd is the Apache HyperText Transfer Protocol (HTTP) server\n       program.  It is designed to be run as a standalone daemon process.\n\n       -d serverroot\n              Set the initial value for the ServerRoot directive.\n\n       -f config\n              Use the directives in the file config on startup.\n              Default: /etc/httpd/conf/httpd.conf\n\n       -k signal\n              Send signal to the running httpd.  Signals: start, restart,\n              graceful, graceful-stop, stop.\n\n       -t     Run syntax tests for configuration files only.\n\n       -v     Print the version of httpd and exit.\n\n       -M     List all loaded modules and exit.\n\nFILES\n       /etc/httpd/conf/httpd.conf      main configuration file\n       /etc/httpd/conf.d/              additional configuration\n       /etc/httpd/conf.modules.d/      module load configuration\n       /var/log/httpd/                 log files\n       /var/www/html/                  default document root\n\nSEE ALSO\n       apachectl(8)\n\nApache HTTP Server               March 2026                       HTTPD(8)",

    'apachectl' => "APACHECTL(8)          System Manager's Manual          APACHECTL(8)\n\nNAME\n       apachectl - Apache HTTP Server Control Interface\n\nSYNOPSIS\n       apachectl command\n\nDESCRIPTION\n       apachectl is a front end to the Apache HyperText Transfer\n       Protocol (HTTP) server.  It is designed to help the administrator\n       control the functioning of the Apache httpd daemon.\n\nCOMMANDS\n       start       Start the Apache daemon.\n       stop        Stop the Apache daemon.\n       restart     Restart the Apache daemon gracefully (SIGHUP).\n       graceful    Graceful restart — open connections are not aborted.\n       fullstatus  Display a full status report from mod_status.\n       status      Display a brief status report.\n       configtest  Run a configuration file syntax test (equivalent to\n                   httpd -t).\n\nFILES\n       /etc/httpd/conf/httpd.conf\n\nSEE ALSO\n       httpd(8)\n\nApache HTTP Server               March 2026                   APACHECTL(8)",

    'fastfetch' => "FASTFETCH(1)              User Commands              FASTFETCH(1)\n\nNAME\n       fastfetch - a fast system information tool\n\nSYNOPSIS\n       fastfetch [OPTIONS]\n\nDESCRIPTION\n       fastfetch is a neofetch-like tool written in C for showing system\n       information and an ASCII distribution logo. It is significantly\n       faster than neofetch due to parallel data acquisition.\n\n       The displayed information includes:\n         OS, Host, Kernel, Uptime, Packages, Shell, Resolution,\n         CPU, Memory, Disk, Load average.\n\nOPTIONS\n       --help\n              Print help message.\n\n       --version\n              Print version.\n\n       --config <path>\n              Load configuration from <path>.\n\n       --logo <name>\n              Override the ASCII logo shown.\n\nFILES\n       ~/.config/fastfetch/config.jsonc\n              User configuration file.\n\nSEE ALSO\n       neofetch(1)\n\nfastfetch                        March 2026                   FASTFETCH(1)",

    'neofetch'  => "NEOFETCH(1)               User Commands               NEOFETCH(1)\n\nNAME\n       neofetch - A fast, highly customizable system info script\n\nSYNOPSIS\n       neofetch [OPTIONS]\n\nDESCRIPTION\n       Neofetch is a command-line system information tool written in bash.\n       Neofetch displays information about your operating system, software\n       and hardware in an aesthetic and visually pleasing way.\n\n       The information is displayed alongside an ASCII image, a distro\n       logo, or any image or video (with w3m or Kitty graphics protocol).\n\nOPTIONS\n       --help\n              Print this text and exit.\n\n       --version\n              Show neofetch version.\n\n       --config /path/to/config\n              Specify a path to a custom config file.\n\n       --off  Disable the ascii image.\n\n       --ascii_distro distro\n              Choose an ascii distro to display.\n\nFILES\n       ~/.config/neofetch/config.conf\n              User configuration file.\n\nSEE ALSO\n       fastfetch(1)\n\nneofetch                         March 2026                    NEOFETCH(1)",

    'head'      => "HEAD(1)                   User Commands                  HEAD(1)\n\nNAME\n       head - output the first part of files\n\nSYNOPSIS\n       head [OPTION]... [FILE]...\n\nDESCRIPTION\n       Print the first 10 lines of each FILE to standard output.\n       With more than one FILE, precede each with a header giving the\n       file name.\n\n       -n, --lines=[-]NUM\n              print the first NUM lines instead of the first 10;\n              with the leading '-', print all but the last NUM lines\n\n       -c, --bytes=[-]NUM\n              print the first NUM bytes of each file;\n              with the leading '-', print all but the last NUM bytes\n\n       -q, --quiet, --silent\n              never print headers giving file names\n\n       -v, --verbose\n              always print headers giving file names\n\nEXAMPLES\n       head file.txt\n              Print first 10 lines of file.txt.\n\n       head -n 20 file.txt\n              Print first 20 lines.\n\n       head -c 100 file.txt\n              Print first 100 bytes.\n\n       head -n5 file.txt\n              Shorthand for -n 5.\n\nAUTHOR\n       Written by David MacKenzie and Jim Meyering.\n\nGNU coreutils                    March 2026                        HEAD(1)",

    'tail'      => "TAIL(1)                   User Commands                  TAIL(1)\n\nNAME\n       tail - output the last part of files\n\nSYNOPSIS\n       tail [OPTION]... [FILE]...\n\nDESCRIPTION\n       Print the last 10 lines of each FILE to standard output.\n       With more than one FILE, precede each with a header giving\n       the file name.\n\n       -n, --lines=[+]NUM\n              output the last NUM lines, instead of the last 10;\n              or use -n +NUM to output starting with line NUM\n\n       -c, --bytes=[+]NUM\n              output the last NUM bytes; or use -c +NUM to output\n              starting with byte NUM\n\n       -f, --follow\n              output appended data as the file grows (simulated —\n              shows last NUM lines with a follow notice)\n\n       -q, --quiet, --silent\n              never output headers giving file names\n\n       -v, --verbose\n              always output headers giving file names\n\nEXAMPLES\n       tail file.txt\n              Print last 10 lines of file.txt.\n\n       tail -n 20 file.txt\n              Print last 20 lines.\n\n       tail -f file.txt\n              Follow file output (simulated).\n\n       tail -c 25 file.txt\n              Print last 25 bytes.\n\n       tail -n +5 file.txt\n              Print from line 5 onwards.\n\n       tail -n10 file.txt\n              Shorthand for -n 10.\n\nAUTHOR\n       Written by Paul Rubin and David MacKenzie.\n\nGNU coreutils                    March 2026                        TAIL(1)",

    'systemctl' => "SYSTEMCTL(1)           systemd                        SYSTEMCTL(1)\n\nNAME\n       systemctl - Control the systemd system and service manager\n\nSYNOPSIS\n       systemctl [OPTIONS...] COMMAND [UNIT...]\n\nDESCRIPTION\n       systemctl may be used to introspect and control the state of the\n       systemd system and service manager.\n\nUNIT COMMANDS\n       start NAME...\n              Start (activate) one or more units specified on the\n              command line.\n\n       stop NAME...\n              Stop (deactivate) one or more units.\n\n       restart NAME...\n              Stop and then start one or more units.\n\n       status [NAME...|PID...]\n              Show terse runtime status information about one or more\n              units, followed by most recent journal log data from the\n              unit.\n\n       enable NAME...\n              Enable one or more units to start at boot.\n\n       disable NAME...\n              Disable one or more units from starting at boot.\n\n       is-active PATTERN...\n              Check whether any of the specified units are active.\n              Returns exit code 0 if at least one is active.\n\n       list-units [PATTERN...]\n              List units that systemd currently has in memory.\n\nEXAMPLES\n       systemctl status httpd\n              Show status of the Apache HTTP server.\n\n       systemctl restart php-fpm\n              Restart the PHP-FPM process manager.\n\n       systemctl enable mariadb\n              Enable MariaDB to start at boot.\n\nFILES\n       /usr/lib/systemd/system/       unit files shipped with packages\n       /etc/systemd/system/           unit files for local configuration\n\nSEE ALSO\n       systemd(1), journalctl(1)\n\nsystemd                          March 2026                    SYSTEMCTL(1)",

    'php'       => "PHP(1)                    User Commands                   PHP(1)\n\nNAME\n       php - PHP Command Line Interface\n\nSYNOPSIS\n       php [options] [-r code] [--] [args...]\n       php [options] [-] [args...]\n       php [options] file [args...]\n\nDESCRIPTION\n       PHP is a widely-used general-purpose scripting language especially\n       suited for web development.\n\nOPTIONS\n       -v, --version\n              Print PHP version.\n\n       -i, --info\n              Print phpinfo() output.\n\n       -r code\n              Run PHP code without using script tags.\n\n       -m\n              List compiled-in modules.\n\n       -f file\n              Parse and execute file.\n\n       -c path\n              Look for php.ini file in this directory.\n\n       -d foo[=bar]\n              Define INI entry foo with value bar.\n\nEXAMPLES\n       php -v\n              Show PHP version.\n\n       php -r 'echo 1+1;'\n              Evaluate an expression.\n\n       php -i | grep memory\n              Show phpinfo and filter for memory settings.\n\n       php -m\n              List all loaded PHP modules.\n\nFILES\n       /etc/php.ini                   main configuration file\n       /etc/php.d/                    additional .ini files loaded automatically\n       /usr/lib64/php/modules/        compiled PHP extensions\n\nSEE ALSO\n       php-fpm(8)\n\nThe PHP Group                    March 2026                         PHP(1)",

    'zip'       => "ZIP(1)                    User Commands                   ZIP(1)\n\nNAME\n       zip - package and compress (archive) files\n\nSYNOPSIS\n       zip [OPTIONS] archive.zip file [file ...]\n\nDESCRIPTION\n       zip is a compression and file packaging utility.  The program places\n       one or more compressed files into a single ZIP archive, along with\n       information about the files (name, path, date, time of last\n       modification, protection, and check information to verify file\n       integrity).\n\nOPTIONS\n       -r, --recurse-paths\n              Travel the directory structure recursively.  For example:\n                zip -r foo.zip foo/\n\n       -v, --verbose\n              Verbose mode.\n\n       -u, --update\n              Replace (update) an existing entry in the zip archive only if\n              it has been modified more recently than the version already in\n              the zip archive.\n\n       -d, --delete\n              Remove (delete) entries from a zip archive.\n\nEXAMPLES\n       zip archive.zip file1.txt file2.txt\n              Create archive.zip from two files.\n\n       zip -r backup.zip /root/\n              Recursively archive the /root directory.\n\nSEE ALSO\n       unzip(1), tar(1)\n\nInfo-ZIP                         March 2026                         ZIP(1)",

    'unzip'     => "UNZIP(1)                  User Commands                 UNZIP(1)\n\nNAME\n       unzip - list, test and extract compressed files in a ZIP archive\n\nSYNOPSIS\n       unzip [OPTIONS] archive.zip [-d exdir]\n\nDESCRIPTION\n       unzip will list, test, or extract files from a ZIP archive, commonly\n       found on MS-DOS systems.\n\nOPTIONS\n       -l     List archive files (short format).\n\n       -v     List archive files verbosely.\n\n       -t     Test archive files.\n\n       -d exdir\n              An optional directory to which to extract files.\n              By default, all files and subdirectories are recreated in\n              the current directory.\n\nEXAMPLES\n       unzip archive.zip\n              Extract all files from archive.zip to the current directory.\n\n       unzip -l archive.zip\n              List the contents of archive.zip.\n\n       unzip archive.zip -d /tmp/\n              Extract archive.zip into /tmp/.\n\nSEE ALSO\n       zip(1), tar(1)\n\nInfo-ZIP                         March 2026                       UNZIP(1)",

        'ln'        => "LN(1)                     User Commands                    LN(1)\n\nNAME\n       ln - make links between files\n\nSYNOPSIS\n       ln [OPTION]... TARGET LINK_NAME\n       ln [OPTION]... TARGET... DIRECTORY\n\nDESCRIPTION\n       Create a link to TARGET with the name LINK_NAME, or create links\n       to each TARGET in DIRECTORY.  Create hard links by default, or\n       symbolic links with -s.\n\n       -s, --symbolic\n              make symbolic links instead of hard links\n\n       -f, --force\n              remove existing destination files\n\n       -n, --no-dereference\n              treat LINK_NAME as a normal file if it is a symbolic link\n              to a directory\n\n       -v, --verbose\n              print name of each linked file\n\nNOTES\n       Hard links are not supported in this terminal — use ln -s for\n       symbolic links.\n\nEXAMPLES\n       ln -s /etc/httpd/conf/httpd.conf httpd.conf\n              Create a symbolic link named httpd.conf in the current\n              directory pointing to the real config file.\n\n       ln -s /usr/lib/os-release /etc/os-release\n              Create a symlink as typically seen on Linux systems.\n\n       ln -s target.txt alias.txt\n              Create alias.txt as a symlink to target.txt.\n\nAUTHOR\n       Written by Mike Parker and David MacKenzie.\n\nGNU coreutils                    March 2026                          LN(1)",

     'rmdir'     => "RMDIR(1)                  User Commands                 RMDIR(1)\n\nNAME\n       rmdir - remove empty directories\n\nSYNOPSIS\n       rmdir [OPTION]... DIRECTORY...\n\nDESCRIPTION\n       Remove the DIRECTORY(ies), if they are empty.\n\n       -p, --parents\n              Remove DIRECTORY and its ancestors.  For example, 'rmdir -p\n              a/b/c' is similar to 'rmdir a/b/c a/b a'.\n\n       -v, --verbose\n              Output a diagnostic for every directory processed.\n\nEXIT STATUS\n       Returns 0 on success, non-zero if any error occurred.\n\nAUTHOR\n       Written by David MacKenzie.\n\nGNU coreutils                    March 2026                       RMDIR(1)",

    'du'        => "DU(1)                     User Commands                    DU(1)\n\nNAME\n       du - estimate file space usage\n\nSYNOPSIS\n       du [OPTION]... [FILE]...\n\nDESCRIPTION\n       Summarize device usage of the set of FILEs, recursively for\n       directories.\n\n       -s, --summarize\n              display only a total for each argument\n\n       -h, --human-readable\n              print sizes in human readable format (e.g., 1K 234M 2G)\n\n       -c, --total\n              produce a grand total\n\n       -d, --max-depth=N\n              print the total for a directory (or file, with --all) only\n              if it is N or fewer levels below the command line argument\n\nEXAMPLES\n       du -sh /var/log\n              Show total size of /var/log in human-readable form.\n\n       du -h /root\n              Show sizes of all files and dirs under /root.\n\nAUTHOR\n       Written by Torbjorn Granlund, David MacKenzie, and Paul Eggert.\n\nGNU coreutils                    March 2026                          DU(1)",

    'diff'      => "DIFF(1)                   User Commands                  DIFF(1)\n\nNAME\n       diff - compare files line by line\n\nSYNOPSIS\n       diff [OPTION]... FILES\n\nDESCRIPTION\n       Compare FILES line by line.\n\n       -u, -U NUM, --unified[=NUM]\n              Output NUM (default 3) lines of unified context.\n\n       -i, --ignore-case\n              Ignore case differences in file contents.\n\n       -r, --recursive\n              Recursively compare any subdirectories found.\n\n       -q, --brief\n              Report only when files differ.\n\n       -s, --report-identical-files\n              Report when two files are the same.\n\nOUTPUT FORMATS\n       Normal format\n              Each hunk is introduced by a line of the form:\n              r1 a r2     lines appended\n              r1 d r2     lines deleted\n              r1 c r2     lines changed\n\n       Unified format (-u)\n              Hunks introduced by @@ -l,s +l,s @@ lines; context\n              lines prefixed with space, deletions with -, additions with +.\n\nEXAMPLES\n       diff file1.txt file2.txt\n              Compare two files.\n\n       diff -u old.conf new.conf\n              Unified diff suitable for a patch file.\n\nAUTHOR\n       Written by Paul Eggert, Mike Haertel, David Hayes, Richard Stallman,\n       and Len Tower.\n\nGNU diffutils                    March 2026                        DIFF(1)",

    'passwd'    => "PASSWD(1)                 User Commands                 PASSWD(1)\n\nNAME\n       passwd - update user's authentication tokens\n\nSYNOPSIS\n       passwd [OPTION...] [LOGIN]\n\nDESCRIPTION\n       The passwd command changes passwords for user accounts.  A normal\n       user may only change the password for their own account, while the\n       superuser may change the password for any account.\n\n       -d, --delete\n              Delete a user's password (make it empty). Available to\n              root only.\n\n       -l, --lock\n              Lock the password of the named account. Available to\n              root only.\n\n       -u, --unlock\n              Unlock the password of the named account. Available to\n              root only.\n\n       -e, --expire\n              Immediately expire an account's password. Available to\n              root only.\n\n       -S, --status\n              Display account status information.\n\nFILES\n       /etc/passwd     user account information\n       /etc/shadow     secure user account information\n\nAUTHOR\n       Written by Marek Michalkiewicz.\n\nshadow-utils                     March 2026                      PASSWD(1)",

    'base64'    => "BASE64(1)                 User Commands                 BASE64(1)\n\nNAME\n       base64 - base64 encode/decode data and print to standard output\n\nSYNOPSIS\n       base64 [OPTION]... [FILE]\n       base64 [OPTION]... <<< STRING\n\nDESCRIPTION\n       Base64 encode or decode FILE, or standard input, to standard output.\n\n       With no FILE, or when FILE is -, read standard input.\n\n       -d, --decode\n              decode data\n\n       -i, --ignore-garbage\n              when decoding, ignore non-alphabet characters\n\n       -w, --wrap=COLS\n              wrap encoded lines after COLS character (default 76);\n              use 0 to disable line wrapping\n\nEXAMPLES\n       base64 <<< \"hello\"\n              Encode the string \"hello\" to base64.\n\n       base64 -d <<< \"aGVsbG8=\"\n              Decode a base64 string.\n\n       echo \"hello\" | base64\n              Pipe input to base64 for encoding.\n\nAUTHOR\n       Written by Simon Josefsson.\n\nGNU coreutils                    March 2026                      BASE64(1)",

    'bc'        => "BC(1)                     User Commands                    BC(1)\n\nNAME\n       bc - arbitrary precision calculator language\n\nSYNOPSIS\n       bc [OPTIONS] [FILE...]\n       bc <<< EXPRESSION\n\nDESCRIPTION\n       bc is a language that supports arbitrary precision numbers with\n       interactive execution of statements. There are some similarities\n       in the syntax to the C programming language.\n\n       -l, --mathlib\n              Define the standard math library.\n\n       -q, --quiet\n              Do not print the normal GNU bc welcome message.\n\n       -s, --standard\n              Process exactly the POSIX bc language.\n\nEXPRESSION SYNTAX\n       Arithmetic operators: + - * / ^ %\n       Grouping: ( )\n\nEXAMPLES\n       bc <<< \"2^10\"\n              Calculate 2 to the power of 10 (result: 1024).\n\n       bc <<< \"(3+4)*2\"\n              Calculate with parentheses (result: 14).\n\n       bc -l <<< \"scale=5; 1/3\"\n              Division with 5 decimal places.\n\nFILES\n       /usr/lib/bc/bc.l    math library (loaded with -l)\n\nAUTHOR\n       Philip A. Nelson. Current maintainer: GNU Project.\n\nGNU bc                           March 2026                          BC(1)",

    'tar'       => "TAR(1)                    User Commands                   TAR(1)\n\nNAME\n       tar - an archiving utility\n\nSYNOPSIS\n       tar [OPTION...] [FILE]...\n\nDESCRIPTION\n       GNU tar is an archiving program designed to store multiple files in a\n       single file (an archive), and to manipulate such archives.\n\nOPERATION MODES\n       -c, --create\n              Create a new archive.\n\n       -x, --extract, --get\n              Extract files from an archive.\n\n       -t, --list\n              List the contents of an archive.\n\nOPTIONS\n       -f, --file=ARCHIVE\n              Use archive file or device ARCHIVE.\n\n       -z, --gzip, --gunzip, --ungzip\n              Filter the archive through gzip.\n\n       -j, --bzip2\n              Filter the archive through bzip2.\n\n       -v, --verbose\n              Verbosely list files processed.\n\nEXAMPLES\n       tar -czf archive.tar.gz dir/\n              Create a gzip-compressed archive of dir/.\n\n       tar -xzf archive.tar.gz\n              Extract a gzip-compressed archive.\n\n       tar -tzf archive.tar.gz\n              List the contents of a gzip-compressed archive.\n\n       tar -cjf archive.tar.bz2 dir/\n              Create a bzip2-compressed archive of dir/.\n\nSEE ALSO\n       zip(1), unzip(1), gzip(1)\n\nGNU tar                          March 2026                         TAR(1)",

    'htop'      => "HTOP(1)                   User Commands                  HTOP(1)\n\nNAME\n       htop - interactive process viewer\n\nSYNOPSIS\n       htop [-d delay] [-u username] [-p pid[,pid...]]\n\nDESCRIPTION\n       htop is an interactive system-monitor process-viewer and\n       process-manager. It is designed as an alternative to the Unix\n       program top.\n\n       htop displays a frequently updated list of the processes running\n       on a computer, normally ordered by the amount of CPU usage.\n       Unlike top, htop provides a full list of processes running,\n       normally ordered by the amount of CPU usage. The display\n       includes per-CPU and memory/swap usage bars at the top.\n\nINTERACTIVE COMMANDS\n       q, F10   Quit\n       F6       Choose sort column\n       F9       Kill selected process\n       F5       Tree view\n       F3       Search processes\n       Up/Down  Move selection\n       Space    Tag/untag process\n\nOPTIONS\n       -d delay\n              Set the delay between updates, in tenths of a second.\n\n       -u username\n              Show only processes owned by username.\n\n       -p pid[,pid...]\n              Show only the given PIDs.\n\n       -s column\n              Sort by the specified column at startup.\n\nAUTHOR\n       Written by Hisham Muhammad.\n\nhtop                             March 2026                        HTOP(1)",

    'sort'      => "SORT(1)                   User Commands                  SORT(1)\n\nNAME\n       sort - sort lines of text files\n\nSYNOPSIS\n       sort [OPTION]... [FILE]...\n\nDESCRIPTION\n       Write sorted concatenation of all FILE(s) to standard output.\n\n       -r, --reverse\n              Reverse the result of comparisons.\n\n       -n, --numeric-sort\n              Compare according to string numerical value.\n\n       -u, --unique\n              With -c, check for strict ordering; without -c, output\n              only the first of an equal run.\n\n       -f, --ignore-case\n              Fold lower case to upper case characters.\n\n       -k, --key=KEYDEF\n              Sort via a key; KEYDEF gives location and type.\n              Example: -k2 sorts on the second whitespace-delimited field.\n\n       -t, --field-separator=SEP\n              Use SEP instead of non-blank to blank transition as the\n              field separator.\n\nEXAMPLES\n       sort file.txt\n              Sort file.txt alphabetically.\n\n       sort -r file.txt\n              Sort in reverse order.\n\n       sort -n numbers.txt\n              Sort numerically.\n\n       sort -u file.txt\n              Sort and remove duplicate lines.\n\n       sort -k2 file.txt\n              Sort by the second field.\n\n       sort -t: -k3 -n /etc/passwd\n              Sort /etc/passwd numerically by the third colon-delimited field.\n\nAUTHOR\n       Written by Mike Haertel and Paul Eggert.\n\nGNU coreutils                    March 2026                        SORT(1)",

    'uniq'      => "UNIQ(1)                   User Commands                  UNIQ(1)\n\nNAME\n       uniq - report or omit repeated lines\n\nSYNOPSIS\n       uniq [OPTION]... [INPUT]\n\nDESCRIPTION\n       Filter adjacent matching lines from INPUT, writing to standard\n       output.\n\n       Note: uniq only compares ADJACENT lines.  To collapse all\n       duplicates in a file, sort it first: sort file | uniq\n\n       -c, --count\n              prefix lines by the number of occurrences\n\n       -d, --repeated\n              only print duplicate lines, one for each group\n\n       -u, --unique\n              only print unique lines (appear exactly once)\n\n       -i, --ignore-case\n              ignore differences in case when comparing\n\nEXAMPLES\n       uniq file.txt\n              Remove adjacent duplicate lines.\n\n       sort file.txt | uniq\n              Remove ALL duplicate lines (sort first).\n\n       uniq -c file.txt\n              Count occurrences of each adjacent group.\n\n       uniq -d file.txt\n              Print only lines that are repeated.\n\n       uniq -u file.txt\n              Print only lines that appear exactly once.\n\nAUTHOR\n       Written by Richard M. Stallman and David MacKenzie.\n\nGNU coreutils                    March 2026                        UNIQ(1)",

    'vim'       => "VIM(1)                    User Commands                   VIM(1)\n\nNAME\n       vim - Vi IMproved, a programmer's text editor\n\nSYNOPSIS\n       vim [OPTIONS] [file ...]\n       vi  [OPTIONS] [file ...]\n\nDESCRIPTION\n       Vim is a text editor that is upwards compatible to Vi. It can be\n       used to edit all kinds of plain text. It is especially useful for\n       editing programs.\n\n       Vim is a modal editor: it operates in several modes.\n\nMODES\n       Normal mode\n              The default mode. Commands move the cursor and operate on\n              the text. Press Escape to return to Normal from any mode.\n\n       Insert mode\n              Text is inserted at the cursor. Enter with i, a, o, O, I, A.\n\n       Command-line mode\n              Entered with : from Normal mode. Used for Ex commands such\n              as :w, :q, :wq.\n\n       Visual mode\n              Entered with v. Select text, then operate on it (y, d).\n\nNORMAL MODE — CURSOR MOVEMENT\n       h j k l    Left / Down / Up / Right\n       w          Move to start of next word\n       b          Move to start of previous word\n       e          Move to end of current word\n       0          Move to start of line\n       $          Move to end of line\n       gg         Go to first line of file\n       G          Go to last line of file\n\nNORMAL MODE — EDITING\n       i          Enter Insert mode before cursor\n       a          Enter Insert mode after cursor\n       I          Enter Insert mode at start of line\n       A          Enter Insert mode at end of line\n       o          Open new line below and enter Insert mode\n       O          Open new line above and enter Insert mode\n       x          Delete character under cursor\n       dd         Delete (cut) current line\n       yy         Yank (copy) current line\n       p          Paste after cursor\n       P          Paste before cursor\n       u          Undo last change\n       /pattern   Search forward for pattern\n       n          Repeat last search (forward)\n       N          Repeat last search (backward)\n       v          Enter Visual mode\n\nINSERT MODE\n       Escape     Return to Normal mode\n       Backspace  Delete character before cursor\n       Enter      Split line at cursor\n\nCOMMAND-LINE MODE (:)\n       :w         Write (save) the file\n       :w file    Write to a different file\n       :q         Quit (fails if unsaved changes)\n       :q!        Quit without saving\n       :wq        Write and quit\n       :x         Write (if modified) and quit\n\nVISUAL MODE\n       y          Yank (copy) selected text\n       d          Delete selected text\n       Escape     Cancel selection\n\nEXAMPLES\n       vim file.txt\n              Open file.txt for editing.\n\n       vim\n              Open Vim with an empty buffer.\n\n       vi /etc/hosts\n              Open /etc/hosts in vi-compatible mode.\n\nAUTHOR\n       Bram Moolenaar et al.\n\nVim 9.1                          March 2026                         VIM(1)",

    'vi'        => "VIM(1)                    User Commands                   VIM(1)\n\nNAME\n       vi - screen-oriented (visual) display editor (alias for vim)\n\nSYNOPSIS\n       vi [OPTIONS] [file]\n\nDESCRIPTION\n       On this system, vi is an alias for vim.  See vim(1) for the\n       full manual.\n\nSEE ALSO\n       vim(1)\n\nVim 9.1                          March 2026                          VI(1)",

    'joe'       => "JOE(1)                    User Commands                   JOE(1)\n\nNAME\n       joe - Joe's Own Editor\n\nSYNOPSIS\n       joe [OPTIONS] [file]\n\nDESCRIPTION\n       joe is a compact, easy-to-use text editor.  It uses ^K (Ctrl+K)\n       as a prefix for most multi-key commands, similar to WordStar and\n       Borland editors.\n\nKEY BINDINGS\n   FILE COMMANDS\n       ^KS        Save the current file (stay in editor)\n       ^KX        Save the current file and exit\n       ^KD        Save file with a new name (Save As)\n       ^KQ        Quit without saving\n       ^KR        Read (insert) another file at cursor\n\n   CURSOR MOVEMENT\n       ^F / ^B    Forward / Backward one character\n       ^N / ^P    Next line / Previous line\n       ^A         Go to beginning of line\n       ^E         Go to end of line\n       Alt+F      Move forward one word\n       Alt+B      Move backward one word\n       ^KU        Go to top of file\n       ^KV        Go to bottom of file\n       Arrow keys Move cursor\n       PageUp/Dn  Scroll by page\n\n   DELETION\n       ^D         Delete character under cursor\n       ^H / BS    Delete character to the left\n       ^Y         Delete (cut) entire line\n       ^W         Delete word to the right\n\n   BLOCK COMMANDS\n       ^KY        Delete marked block (or current line)\n       ^KC        Copy (paste cut buffer at cursor)\n       ^KM        Move (paste cut buffer at cursor)\n\n   SEARCH\n       ^KF        Find a string (enter search term, press Enter)\n       ^L         Repeat last search\n\n   HELP\n       ^KH        Toggle built-in help screen\n       F1         Toggle built-in help screen\n\nEXAMPLES\n       joe file.txt\n              Open file.txt for editing.\n\n       joe\n              Open joe with an empty buffer.\n\nAUTHOR\n       Written by Joseph H. Allen.\n\njoe                              March 2026                         JOE(1)",

    'exa'       => "EXA(1)                    User Commands                   EXA(1)\n\nNAME\n       exa - a modern replacement for ls\n\nSYNOPSIS\n       exa [OPTIONS] [FILES...]\n\nDESCRIPTION\n       exa is an improved file lister with more features and better\n       defaults than ls. It uses colours to distinguish file types and\n       metadata, and knows about symlinks, extended attributes, and Git.\n\nDISPLAY OPTIONS\n       -1, --oneline\n              Display one entry per line.\n\n       -l, --long\n              Display extended file metadata as a table.\n\n       -G, --grid\n              Display entries as a grid (default).\n\n       -T, --tree\n              Recurse into directories as a tree.\n\n       -R, --recurse\n              Recurse into directories.\n\n       -a, --all\n              Show hidden and 'dot' files.\n\n       --icons\n              Display icons (requires a Nerd Font).\n\n       --git\n              List each file's Git status, if tracked or ignored.\n\n       -h, --header\n              Add a header row to each column.\n\nFILTERING AND SORTING\n       -r, --reverse\n              Reverse the sort order.\n\n       -s, --sort SORT_FIELD\n              Which field to sort by: name, size, date, type, ext.\n\nEXAMPLES\n       exa\n              List files in current directory.\n\n       exa --long --git\n              Long listing with Git status.\n\n       exa --tree --level=2\n              Tree view two levels deep.\n\n       exa -la\n              Long listing including hidden files.\n\nSEE ALSO\n       ls(1)\n\nexa                              March 2026                         EXA(1)",

    'firewall-cmd' => "FIREWALL-CMD(1)           User Commands            FIREWALL-CMD(1)\n\nNAME\n       firewall-cmd - firewalld command line client\n\nSYNOPSIS\n       firewall-cmd [OPTIONS...]\n\nDESCRIPTION\n       firewall-cmd is the command line client of the firewalld daemon.\n       It provides interface to manage runtime and permanent\n       configuration.\n\nGENERAL OPTIONS\n       --state\n              Return and print firewalld state.\n\n       --reload\n              Reload firewall rules and keep state information.\n\nZONE OPTIONS\n       --list-all\n              List everything added for or enabled in the default zone.\n\n       --list-ports\n              List ports that have been added to the default zone.\n\n       --add-port=PORT/PROTOCOL [--permanent]\n              Add port and protocol to the default zone.\n              Example: --add-port=8080/tcp\n\n       --remove-port=PORT/PROTOCOL [--permanent]\n              Remove port from the default zone.\n\n       --add-service=SERVICE [--permanent]\n              Add a service to the default zone.\n\n       --remove-service=SERVICE [--permanent]\n              Remove a service from the default zone.\n\nEXAMPLES\n       firewall-cmd --state\n              Print current firewalld state (running/not running).\n\n       firewall-cmd --list-all\n              Show all rules for the default zone.\n\n       firewall-cmd --add-port=8080/tcp --permanent\n              Permanently open port 8080/tcp.\n\n       firewall-cmd --reload\n              Reload firewall rules.\n\nFILES\n       /etc/firewalld/                   configuration directory\n       /etc/firewalld/firewalld.conf     main configuration file\n       /etc/firewalld/zones/             zone configuration files\n\nSEE ALSO\n       firewalld(1), firewalld.conf(5)\n\nfirewalld                        March 2026                FIREWALL-CMD(1)",

    'telnet'    => "TELNET(1)                 User Commands                 TELNET(1)\n\nNAME\n       telnet - user interface to the TELNET protocol\n\nSYNOPSIS\n       telnet [HOST [PORT]]\n\nDESCRIPTION\n       The telnet command is used for interactive communication with\n       another host using the TELNET protocol.  It begins in command\n       mode, where it prints a telnet> prompt and accepts the\n       commands listed below.\n\n       If telnet is invoked with a host argument, it performs an\n       open command implicitly.\n\nOPTIONS\n       HOST   Specifies a host to contact over the network.\n\n       PORT   Specifies a port number. If not specified, the\n              default telnet port is used (port 23).\n\nNOTE\n       Telnet is an unencrypted protocol and should not be used\n       on untrusted networks. Use SSH instead where possible.\n\nEXAMPLES\n       telnet router.local\n              Connect to router.local on port 23.\n\n       telnet 192.168.1.1 8023\n              Connect to 192.168.1.1 on port 8023.\n\nSEE ALSO\n       ssh(1), nc(1)\n\nLinux NetKit                     March 2026                      TELNET(1)",

    'find'      => "FIND(1)                   User Commands                  FIND(1)\n\nNAME\n       find - search for files in a directory hierarchy\n\nSYNOPSIS\n       find [PATH...] [EXPRESSION]\n\nDESCRIPTION\n       find searches the directory tree rooted at each given PATH for\n       files matching the given EXPRESSION.\n\nTESTS\n       -name PATTERN\n              True if the base of the file name matches the shell PATTERN.\n              Use quotes around patterns containing wildcards.\n              Examples: -name '*.log'  -name 'config.*'\n\n       -type c\n              True if the file is of type c:\n              f   regular file\n              d   directory\n\n       -maxdepth N\n              Descend at most N levels of directories below the\n              command-line arguments.  -maxdepth 0 applies tests and\n              actions to the command-line arguments themselves.\n\n       -mindepth N\n              Do not apply any tests or actions at levels less than N.\n\n       -size N[ckMG]\n              True if the file uses N units of space:\n              c   bytes\n              k   kilobytes (1024 bytes)\n              M   megabytes\n              G   gigabytes\n              A leading + means strictly greater than; - means less than.\n\n       -not / !\n              Invert the truth value of the next test.\n\nACTIONS\n       -print Print the full path of the matching file (default action).\n\n       -delete\n              Delete matching files.\n\nEXAMPLES\n       find /etc -name 'cron*'\n              Find all files/dirs under /etc whose name starts with cron.\n\n       find . -type f -name '*.conf'\n              Find all regular files ending in .conf in current tree.\n\n       find /var/log -type f -name '*.log' -maxdepth 1\n              Find *.log files directly inside /var/log (not subdirs).\n\n       find /tmp -maxdepth 1 -type f -delete\n              Delete regular files directly under /tmp.\n\n       find / -type f -size +1M\n              Find files larger than 1 megabyte anywhere in the tree.\n\nAUTHOR\n       Written by Eric Decker, James Youngman, and Kevin Dalley.\n\nGNU findutils                    March 2026                        FIND(1)",

    'su'        => "SU(1)                     User Commands                    SU(1)\n\nNAME\n       su - run a command with substitute user and group ID\n\nSYNOPSIS\n       su [OPTIONS] [USER [ARG...]]\n\nDESCRIPTION\n       su allows commands to be run with a substitute user and group ID.\n\n       When called with no USER specified, su defaults to becoming root.\n\n       For backward compatibility, su defaults to not change the current\n       directory and only sets the environment variables HOME and SHELL\n       (plus USER and LOGNAME if the target USER is not root).\n\n       The following options can be passed to su:\n\n       -, -l, --login\n              Start the shell as a login shell with an environment\n              similar to a real login: clears all environment variables\n              except for TERM and sets HOME, SHELL, USER, LOGNAME, and PATH.\n\n       -c CMD, --command=CMD\n              Pass CMD to the shell with the -c option.\n\n       -s SHELL, --shell=SHELL\n              Run the specified shell instead of the default.\n\n       -m, -p, --preserve-environment\n              Preserve the entire environment.\n\nEXAMPLES\n       su\n              Become root (prompts for root password if not already root).\n\n       su -\n              Become root with a full login environment.\n\n       su - deploy\n              Switch to deploy user with a fresh login environment.\n\n       su -c 'ls /root' root\n              Run ls /root as root without a persistent session.\n\nFILES\n       /etc/passwd    user account information\n       /etc/shadow    encrypted passwords\n       /etc/pam.d/su  PAM configuration for su\n\nSEE ALSO\n       sudo(8), passwd(1)\n\nutil-linux                       March 2026                          SU(1)",

    'sendmail'  => "SENDMAIL(8)           System Manager's Manual          SENDMAIL(8)\n\nNAME\n       sendmail - an electronic mail transport agent\n\nSYNOPSIS\n       sendmail [flags] [address ...]\n       sendmail -t [flags]\n\nDESCRIPTION\n       sendmail sends a message to one or more recipients, routing\n       the message over whatever networks are necessary.\n\n       In this simulated environment, sendmail connects to localhost\n       on port 25 and queues the message for delivery.\n\nOPTIONS\n       address\n              One or more recipient addresses.\n\n       -v     Go into verbose mode.\n\n       -t     Read the message for recipients. To:, Cc:, and Bcc:\n              lines will be scanned for recipient addresses.\n\n       -f address\n              Set the name of the 'from' person (the envelope sender\n              of the message).\n\n       -F fullname\n              Set the full name of the sender.\n\nEXAMPLES\n       sendmail user@example.com\n              Queue a message to user@example.com.\n\n       sendmail -v admin@example.com\n              Send with verbose SMTP conversation.\n\n       sendmail -t\n              Read message from stdin, extract recipients from headers.\n\nFILES\n       /etc/mail/sendmail.cf      main configuration file\n       /var/spool/mqueue/         mail queue directory\n\nSEE ALSO\n       mail(1), postfix(1)\n\nSendmail                         March 2026                     SENDMAIL(8)",

    'mysql'     => "MYSQL(1)                  User Commands                  MYSQL(1)\n\nNAME\n       mysql - the MariaDB command-line tool\n\nSYNOPSIS\n       mysql [OPTIONS] [database]\n\nDESCRIPTION\n       mysql is a simple SQL shell with input line editing capabilities.\n       It supports interactive and non-interactive use.  When used\n       interactively, query results are presented in an ASCII-table format.\n\nOPTIONS\n       -u USER, --user=USER\n              The MariaDB user name to use when connecting to the server.\n              Default: root\n\n       -p, --password\n              Prompt for a password before connecting.\n\n       -h HOST, --host=HOST\n              Connect to the MariaDB server on the given host.\n              Default: localhost\n\n       -P PORT, --port=PORT\n              The TCP/IP port number to use for the connection.\n              Default: 3306\n\n       -e STATEMENT, --execute=STATEMENT\n              Execute the statement and quit.\n\n       database\n              The name of the database to use. The database can also\n              be changed later with the USE command.\n\nCOMMANDS\n       Commands inside the mysql shell:\n\n       SHOW DATABASES;          List all databases\n       USE db;                  Select a database\n       SHOW TABLES;             List tables in current database\n       DESCRIBE table;          Show table structure\n       SELECT * FROM table;     Query a table\n       SHOW PROCESSLIST;        List active connections\n       SHOW STATUS;             Server status variables\n       SHOW VARIABLES;          Server system variables\n       quit / exit / \\q         Exit mysql\n       help / \\h                Show help\n       status / \\s              Print server status\n       \\c                       Clear the current input statement\n\nEXAMPLES\n       mysql -u root -p\n              Connect as root (prompts for password).\n\n       mysql -u root production\n              Connect as root and select the production database.\n\n       mysql -u deploy -p production\n              Connect as deploy user to the production database.\n\nFILES\n       /etc/my.cnf               global options\n       /etc/my.cnf.d/            additional option files\n       /var/lib/mysql/mysql.sock UNIX socket\n\nSEE ALSO\n       mysqldump(1), mysqladmin(1)\n\nMariaDB                          March 2026                       MYSQL(1)",

    'mariadb'   => "MARIADB(1)                User Commands                MARIADB(1)\n\nNAME\n       mariadb - the MariaDB command-line tool (alias for mysql)\n\nSYNOPSIS\n       mariadb [OPTIONS] [database]\n\nDESCRIPTION\n       mariadb is the MariaDB 10.4+ name for the mysql command-line client.\n       See mysql(1) for full documentation.\n\nSEE ALSO\n       mysql(1)\n\nMariaDB                          March 2026                    MARIADB(1)",

    'awk'       => "AWK(1)                    User Commands                   AWK(1)\n\nNAME\n       awk - pattern scanning and processing language\n\nSYNOPSIS\n       awk [OPTIONS] 'PROGRAM' [FILE...]\n       awk [OPTIONS] -f PROGFILE [FILE...]\n\nDESCRIPTION\n       awk scans each input FILE for lines that match any of a set of\n       patterns specified in PROGRAM.  For each matching line, the\n       associated action is performed.\n\nOPTIONS\n       -F SEP\n              Set the input field separator to SEP (default: whitespace).\n\n       -v VAR=VAL\n              Assign VAL to program variable VAR before execution.\n\n       -f PROGFILE\n              Read the awk program from PROGFILE instead of the first\n              argument.\n\nBUILT-IN VARIABLES\n       NR     Current record (line) number.\n       NF     Number of fields in current record.\n       FS     Input field separator (default: whitespace).\n       OFS    Output field separator (default: space).\n       RS     Input record separator (default: newline).\n       ORS    Output record separator (default: newline).\n       $0     Entire current record.\n       $1..$NF  Individual fields.\n\nSPECIAL PATTERNS\n       BEGIN  Executed before any input is read.\n       END    Executed after all input has been processed.\n\nBUILT-IN FUNCTIONS\n       length([s])        Length of string s (or $0).\n       substr(s, m [, n]) Substring of s starting at position m.\n       index(s, t)        Position of t in s (0 if not found).\n       split(s, a [, fs]) Split s into array a using fs.\n       sub(r, s [, t])    Substitute first match of regex r with s in t.\n       gsub(r, s [, t])   Substitute all matches of regex r with s in t.\n       toupper(s)         Return s converted to upper case.\n       tolower(s)         Return s converted to lower case.\n       sprintf(fmt, ...)  Format string like printf.\n\nEXAMPLES\n       awk '{print $1}' file.txt\n              Print the first field of each line.\n\n       awk -F: '{print $1, $3}' /etc/passwd\n              Print username and UID from /etc/passwd.\n\n       awk 'NR==1' file.txt\n              Print only the first line.\n\n       awk '{sum += $1} END {print sum}' numbers.txt\n              Sum all values in the first column.\n\n       awk '/error/ {print NR\": \"$0}' log.txt\n              Print line number and content for lines matching /error/.\n\n       awk 'BEGIN{FS=\":\"; OFS=\"\\t\"} {print $1,$6}' /etc/passwd\n              Print username and home directory, tab-separated.\n\nAUTHOR\n       Alfred Aho, Peter Weinberger, Brian Kernighan.\n       GNU awk (gawk) by Arnold Robbins.\n\nGNU awk                          March 2026                         AWK(1)",

    'sed'       => "SED(1)                    User Commands                   SED(1)\n\nNAME\n       sed - stream editor for filtering and transforming text\n\nSYNOPSIS\n       sed [OPTIONS] SCRIPT [FILE...]\n       sed [OPTIONS] -e SCRIPT [-e SCRIPT] [FILE...]\n\nDESCRIPTION\n       sed is a stream editor used to perform basic text transformations\n       on an input stream (a file or input from a pipeline).\n\nOPTIONS\n       -n, --quiet, --silent\n              Suppress automatic printing of pattern space.\n\n       -e SCRIPT, --expression=SCRIPT\n              Add the script to the commands to be executed.\n\n       -i[SUFFIX], --in-place[=SUFFIX]\n              Edit files in-place (makes backup if SUFFIX supplied).\n              In this terminal, -i updates the session filesystem.\n\nCOMMANDS\n       s/REGEXP/REPLACEMENT/[FLAGS]\n              Substitute. FLAGS: g (global), i (ignore case),\n              p (print), N (replace Nth occurrence).\n\n       d      Delete pattern space.\n\n       p      Print pattern space.\n\n       q      Quit (stop processing).\n\n       =      Print current line number.\n\n       y/SET1/SET2/\n              Transliterate: replace characters in SET1 with\n              corresponding characters in SET2.\n\n       a\\TEXT  Append TEXT after the current line.\n\n       i\\TEXT  Insert TEXT before the current line.\n\nADDRESSING\n       Commands can be prefixed with an address to limit which lines\n       they apply to:\n\n       N      Line number N.\n       $      Last line.\n       /REGEXP/  Lines matching REGEXP.\n       N,M    Range from line N to M.\n       /RE1/,/RE2/  Range from first /RE1/ match to next /RE2/ match.\n\nEXAMPLES\n       sed 's/foo/bar/' file.txt\n              Replace first occurrence of 'foo' with 'bar' per line.\n\n       sed 's/foo/bar/g' file.txt\n              Replace all occurrences of 'foo' with 'bar'.\n\n       sed -n '5,10p' file.txt\n              Print only lines 5 through 10.\n\n       sed '/^#/d' file.txt\n              Delete all comment lines (starting with #).\n\n       sed -n '/error/p' log.txt\n              Print only lines containing 'error'.\n\n       sed '1s/^/HEADER\\n/' file.txt\n              Insert HEADER before the first line.\n\n       sed -i 's/localhost/127.0.0.1/g' config.txt\n              Edit config.txt in place, replacing all occurrences.\n\nAUTHOR\n       Written by Lee E. McMahon. GNU sed by Tom Lord and others.\n\nGNU sed                          March 2026                         SED(1)",

    'lsblk'     => "LSBLK(8)              System Manager's Manual             LSBLK(8)\n\nNAME\n       lsblk - list block devices\n\nSYNOPSIS\n       lsblk [options] [device...]\n\nDESCRIPTION\n       lsblk lists information about all available block devices.\n       The lsblk command reads the sysfs filesystem and udev database\n       to gather information.\n\nOPTIONS\n       -f, --fs\n              Output info about filesystems (UUID, label, type, etc.).\n\n       -J, --json\n              Use JSON output format.\n\n       -p, --paths\n              Print full device paths.\n\n       -t, --topology\n              Output info about block-device topology.\n\nCOLUMNS\n       NAME    Device name.\n       MAJ:MIN Major and minor device number.\n       RM      Removable device flag.\n       SIZE    Size of the device.\n       RO      Read-only flag.\n       TYPE    Device type (disk, part, rom, etc.).\n       MOUNTPOINTS  Where the device is mounted.\n\nAUTHOR\n       Written by Milan Broz.\n\nutil-linux                       March 2026                      LSBLK(8)",

    'blkid'     => "BLKID(8)              System Manager's Manual             BLKID(8)\n\nNAME\n       blkid - locate/print block device attributes\n\nSYNOPSIS\n       blkid [options] [device...]\n\nDESCRIPTION\n       blkid determines the type of content (e.g. filesystem or swap)\n       that a block device holds, and also the attributes (tokens,\n       NAME=value pairs) from the content metadata (e.g. LABEL or UUID).\n\nOPTIONS\n       -L label\n              Look up the device that has the specified LABEL.\n\n       -U uuid\n              Look up the device that has the specified UUID.\n\n       -s tag\n              Only print the given tag for the device(s).\n\nAUTHOR\n       Written by Andreas Dilger.\n\nutil-linux                       March 2026                      BLKID(8)",

    'dmesg'     => "DMESG(1)                  User Commands                  DMESG(1)\n\nNAME\n       dmesg - print or control the kernel ring buffer\n\nSYNOPSIS\n       dmesg [options]\n\nDESCRIPTION\n       dmesg is used to examine or control the kernel ring buffer.\n\nOPTIONS\n       -T, --ctime\n              Print human-readable timestamps.\n\n       -n level\n              Set the level at which logging of messages is done to the\n              console.\n\n       -w, --follow\n              Wait for new messages.\n\n       -H, --human\n              Enable human-readable output.\n\n       --level list\n              Restrict output to the given levels. Comma-separated list\n              of: emerg, alert, crit, err, warn, notice, info, debug.\n\nAUTHOR\n       Written by Theodore Ts'o.\n\nutil-linux                       March 2026                      DMESG(1)",

    'vmstat'    => "VMSTAT(8)             System Manager's Manual            VMSTAT(8)\n\nNAME\n       vmstat - report virtual memory statistics\n\nSYNOPSIS\n       vmstat [options] [delay [count]]\n\nDESCRIPTION\n       vmstat reports information about processes, memory, paging, block\n       I/O, traps, disks and CPU activity.\n\nOPTIONS\n       -a, --active\n              Display active and inactive memory.\n\n       -s, --stats\n              Display a table of various event counters and memory stats.\n\n       -S unit\n              Switches outputs between 1000 (k), 1024 (K), 1000000 (m),\n              or 1048576 (M) bytes.\n\nFIELDS\n       procs  r: processes waiting for run time.  b: in uninterruptible sleep.\n       memory swpd, free, buff, cache in kilobytes.\n       swap   si: from disk/s.  so: to disk/s.\n       io     bi: blocks received from block device.  bo: blocks sent.\n       system in: interrupts/s.  cs: context switches/s.\n       cpu    us sy id wa st: percentages of cpu time.\n\nAUTHOR\n       Written by Henry Ware.\n\nprocps-ng                        March 2026                     VMSTAT(8)",

    'iostat'    => "IOSTAT(1)                 User Commands                  IOSTAT(1)\n\nNAME\n       iostat - report CPU and I/O statistics for devices and partitions\n\nSYNOPSIS\n       iostat [options] [interval [count]]\n\nDESCRIPTION\n       The iostat command monitors system I/O device loading by observing\n       the time devices are active relative to their average transfer rates.\n\nOPTIONS\n       -c     Display the CPU utilization report only.\n\n       -d     Display the device utilization report only.\n\n       -h, --human\n              Display statistics in human-readable format.\n\n       -k     Display statistics in kilobytes per second.\n\n       -m     Display statistics in megabytes per second.\n\n       -x     Display extended statistics.\n\n       -z     Omit output for any devices with no activity.\n\nAUTHOR\n       Written by Sebastien Godard.\n\nsysstat                          March 2026                     IOSTAT(1)",

    'hostnamectl' => "HOSTNAMECTL(1)         systemd                        HOSTNAMECTL(1)\n\nNAME\n       hostnamectl - Control the system hostname\n\nSYNOPSIS\n       hostnamectl [OPTIONS...] COMMAND\n\nDESCRIPTION\n       hostnamectl may be used to query and change the system hostname\n       and related settings.\n\nCOMMANDS\n       status\n              Show current system hostname and related information.\n              This is the implied default.\n\n       set-hostname NAME\n              Set the system hostname to NAME.\n\nOPTIONS\n       --static\n              Only show or set the static hostname.\n\n       --transient\n              Only show or set the transient hostname.\n\n       --pretty\n              Only show or set the pretty hostname.\n\nsystemd                          March 2026                 HOSTNAMECTL(1)",

    'timedatectl' => "TIMEDATECTL(1)         systemd                        TIMEDATECTL(1)\n\nNAME\n       timedatectl - Control the system time and date\n\nSYNOPSIS\n       timedatectl [OPTIONS...] COMMAND\n\nDESCRIPTION\n       timedatectl may be used to query and change the system clock\n       and its settings.\n\nCOMMANDS\n       status\n              Show current time settings. This is the implied default.\n\n       set-time TIME\n              Set the system clock. Format: \"2026-03-25 14:00:00\".\n\n       set-timezone TIMEZONE\n              Set the system time zone (e.g. Europe/Amsterdam).\n\n       list-timezones\n              List available time zones.\n\n       set-ntp BOOL\n              Enable or disable NTP synchronization.\n\nsystemd                          March 2026                 TIMEDATECTL(1)",

    'chgrp'     => "CHGRP(1)                  User Commands                  CHGRP(1)\n\nNAME\n       chgrp - change group ownership\n\nSYNOPSIS\n       chgrp [OPTION]... GROUP FILE...\n\nDESCRIPTION\n       Change the group of each FILE to GROUP.\n\n       -R, --recursive\n              Operate on files and directories recursively.\n\n       -v, --verbose\n              Output a diagnostic for every file processed.\n\nNOTE\n       In this terminal, chgrp is cosmetic — it accepts arguments\n       and exits silently without modifying session state.\n\nAUTHOR\n       Written by David MacKenzie and Jim Meyering.\n\nGNU coreutils                    March 2026                     CHGRP(1)",

    'logger'    => "LOGGER(1)                 User Commands                  LOGGER(1)\n\nNAME\n       logger - enter messages into the system log\n\nSYNOPSIS\n       logger [options] [message]\n\nDESCRIPTION\n       logger makes entries in the system log. It provides a shell\n       command interface to the syslog(3) system log module.\n\nOPTIONS\n       -p, --priority priority\n              Enter the message with the specified priority.\n              Format: facility.level (e.g. local3.info). Default: user.notice.\n\n       -t, --tag tag\n              Mark every line in the log with the specified tag.\n\n       -s, --stderr\n              Output the message to standard error as well.\n\n       -n, --server server\n              Write to the specified remote syslog server.\n\nEXAMPLES\n       logger Hello, syslog!\n\n       logger -p local0.err 'Disk quota exceeded'\n\nNOTE\n       In this terminal, logger silently accepts the message and exits.\n\nutil-linux                       March 2026                     LOGGER(1)",

    'netstat'   => "NETSTAT(8)            System Manager's Manual           NETSTAT(8)\n\nNAME\n       netstat - print network connections, routing tables, interface\n                 statistics, masquerade connections, and multicast memberships\n\nSYNOPSIS\n       netstat [-a] [-n] [-p] [-t] [-u] [-l] [-r]\n\nDESCRIPTION\n       netstat prints information about the Linux networking subsystem.\n\nOPTIONS\n       -a, --all\n              Show both listening and non-listening sockets.\n\n       -n, --numeric\n              Show numerical addresses instead of resolving hostnames.\n\n       -p, --program\n              Show the PID and name of the program to which each socket\n              belongs.\n\n       -t, --tcp\n              Show only TCP connections.\n\n       -u, --udp\n              Show only UDP connections.\n\n       -l, --listening\n              Show only listening sockets.\n\n       -r, --route\n              Display the kernel routing table.\n\nEXAMPLES\n       netstat -an\n              Show all connections with numeric addresses.\n\n       netstat -tlnp\n              Show TCP listening sockets with PID info.\n\n       netstat -r\n              Show the routing table.\n\nNOTE\n       netstat is part of net-tools, which is deprecated in favour of\n       the ss command from iproute2.\n\nnet-tools                        March 2026                     NETSTAT(8)",

    'ss'        => "SS(8)                 System Manager's Manual               SS(8)\n\nNAME\n       ss - another utility to investigate sockets\n\nSYNOPSIS\n       ss [options]\n\nDESCRIPTION\n       ss is used to dump socket statistics. It allows showing information\n       similar to netstat. It can display more TCP and state information\n       than other tools.\n\nOPTIONS\n       -a, --all\n              Display all sockets (default: connected sockets only).\n\n       -l, --listening\n              Display only listening sockets.\n\n       -n, --numeric\n              Do not try to resolve service names.\n\n       -p, --processes\n              Show process using socket.\n\n       -t, --tcp\n              Display TCP sockets.\n\n       -u, --udp\n              Display UDP sockets.\n\nEXAMPLES\n       ss -tlnp\n              Show TCP listening sockets with process info.\n\n       ss -an\n              Show all sockets with numeric addresses.\n\niproute2                         March 2026                          SS(8)",

    'ssh'       => "SSH(1)                    User Commands                   SSH(1)\n\nNAME\n       ssh - OpenSSH remote login client\n\nSYNOPSIS\n       ssh [-46AaCfGgKkMNnqsTtVvXxYy] [-p port] [-i identity_file]\n           [-l login_name] destination [command]\n\nDESCRIPTION\n       ssh  (SSH client) is a program for logging into a remote machine and\n       for executing commands on a remote machine.\n\n       -p port\n              Port to connect to on the remote host.\n\n       -i identity_file\n              Selects a file from which the identity (private key) for\n              public key authentication is read.\n\n       -l login_name\n              Specifies the user to log in as on the remote machine.\n\n       -v     Verbose mode. Multiple -v options increase the verbosity.\n\n       -v -v -v\n              Maximum verbosity (debug level 3).\n\nEXAMPLES\n       ssh root@192.168.1.10\n              Connect as root to 192.168.1.10.\n\n       ssh -p 2222 user@server.example.com\n              Connect on a non-standard port.\n\n       ssh -v git@github.com\n              Test GitHub SSH connectivity verbosely.\n\nNOTE\n       In this terminal, ssh to non-localhost hosts returns a\n       'Connection refused' response (simulated).\n\nOpenSSH                          March 2026                         SSH(1)",

    'dig'       => "DIG(1)                    User Commands                   DIG(1)\n\nNAME\n       dig - DNS lookup utility\n\nSYNOPSIS\n       dig [@server] name [type]\n\nDESCRIPTION\n       dig (domain information groper) is a flexible tool for interrogating\n       DNS name servers. It performs DNS lookups and displays the answers\n       that are returned from the queried name server(s).\n\nOPTIONS\n       @server\n              The name or IP address of the name server to query.\n              If not provided, the servers in /etc/resolv.conf are used.\n\n       name   The name of the resource record to be looked up.\n\n       type   Indicates what type of query is required — ANY, A, MX,\n              AAAA, NS, TXT, SOA, PTR, CNAME. Default: A.\n\nEXAMPLES\n       dig google.com\n              Look up the A record for google.com.\n\n       dig google.com MX\n              Look up mail exchange records for google.com.\n\n       dig @8.8.8.8 github.com\n              Query Google's public DNS for github.com.\n\n       dig google.com NS\n              Show the name servers for google.com.\n\nSEE ALSO\n       host(1), nslookup(1)\n\nBIND 9                           March 2026                         DIG(1)",

    'host'      => "HOST(1)                   User Commands                  HOST(1)\n\nNAME\n       host - DNS lookup utility\n\nSYNOPSIS\n       host [-aCdilrTvVw] [-c class] [-t type] [-W time]\n            hostname [server]\n\nDESCRIPTION\n       host is a simple utility for performing DNS lookups. It is normally\n       used to convert names to IP addresses and vice versa.\n\nOPTIONS\n       -t type\n              Query type: A, AAAA, MX, NS, TXT, CNAME, SOA.\n\n       -a     Equivalent to -v -t ANY.\n\n       -v     Verbose output.\n\nEXAMPLES\n       host google.com\n              Show the A record for google.com.\n\n       host -t MX google.com\n              Show mail exchangers for google.com.\n\n       host 8.8.8.8\n              Reverse lookup of 8.8.8.8.\n\nSEE ALSO\n       dig(1), nslookup(1)\n\nBIND 9                           March 2026                        HOST(1)",

    'journalctl' => "JOURNALCTL(1)          systemd                        JOURNALCTL(1)\n\nNAME\n       journalctl - Query the systemd journal\n\nSYNOPSIS\n       journalctl [OPTIONS...] [MATCHES...]\n\nDESCRIPTION\n       journalctl may be used to query the contents of the systemd(1)\n       journal as written by systemd-journald.service(8).\n\nOPTIONS\n       -u, --unit=UNIT\n              Show messages for the specified systemd unit.\n              Example: journalctl -u httpd\n\n       -n, --lines=N\n              Show the most recent N journal entries.\n              Default: 10.\n\n       -f, --follow\n              Show only the most recent journal entries, and continuously\n              print new entries as they are appended to the journal.\n\n       -r, --reverse\n              Reverse output so that the newest entries are listed first.\n\n       --since=DATE\n              Start showing entries on or newer than the specified date,\n              or 'yesterday', 'today'.\n\nEXAMPLES\n       journalctl -u httpd\n              Show all logs for the Apache HTTP Server.\n\n       journalctl -u mariadb -n 20\n              Show the last 20 lines from the MariaDB log.\n\n       journalctl -f\n              Follow the journal in real time.\n\n       journalctl --since today\n              Show entries from today.\n\nFILES\n       /var/log/journal/    persistent journal storage\n\nSEE ALSO\n       systemctl(1), systemd(1)\n\nsystemd                          March 2026                  JOURNALCTL(1)",

    'lsof'      => "LSOF(8)               System Manager's Manual              LSOF(8)\n\nNAME\n       lsof - list open files\n\nSYNOPSIS\n       lsof [-i [address]] [-p PID] [-u USER] [name]\n\nDESCRIPTION\n       lsof lists information about files opened by processes. An open\n       file may be a regular file, a directory, a block special file, a\n       character special file, an executing text reference, a library,\n       a stream or a network file (Internet socket, NFS file or UNIX\n       domain socket).\n\nOPTIONS\n       -i [address]\n              List files whose Internet address matches the specified\n              address. Example: -i :80  -i TCP:22  -i @192.168.1.1\n\n       -p PID\n              List files for the process with the specified PID.\n\n       -u USER\n              List files for the user with the specified login name.\n\n       -n     Do not convert network numbers to host names.\n\n       -P     Do not convert port numbers to port names.\n\nOUTPUT COLUMNS\n       COMMAND   Process name.\n       PID       Process ID.\n       USER      Login name.\n       FD        File descriptor (e.g. 4u = fd 4, r/w).\n       TYPE      File type (IPv4, IPv6, REG, DIR, CHR, etc.).\n       DEVICE    Device numbers.\n       SIZE      File size or offset.\n       NODE      Inode or protocol.\n       NAME      Name of the file or socket address.\n\nEXAMPLES\n       lsof -i :80\n              List processes listening on port 80.\n\n       lsof -u apache\n              List files opened by user apache.\n\n       lsof -p 1234\n              List files opened by PID 1234.\n\n       lsof -i TCP\n              List all TCP sockets.\n\nlsof                             March 2026                        LSOF(8)",

    'pushd'     => "PUSHD(1)               bash built-in                   PUSHD(1)\n\nNAME\n       pushd - save and change the current directory\n\nSYNOPSIS\n       pushd [dir]\n       pushd +N\n\nDESCRIPTION\n       Adds a directory to the top of the directory stack, or rotates\n       the stack, making the new top of the stack the current directory.\n       With no arguments, exchanges the top two directories.\n\nEXAMPLES\n       pushd /var/log\n              Push /var/log onto the stack and cd there.\n\n       pushd\n              Swap the top two entries on the stack.\n\nSEE ALSO\n       popd(1), dirs(1)\n\nGNU bash                         March 2026                      PUSHD(1)",

    'popd'      => "POPD(1)                bash built-in                    POPD(1)\n\nNAME\n       popd - remove entries from the directory stack\n\nSYNOPSIS\n       popd [+N]\n\nDESCRIPTION\n       Removes entries from the directory stack. With no arguments,\n       removes the top directory from the stack and cd's to the new\n       top directory.\n\nEXAMPLES\n       popd\n              Pop the directory stack and return to the previous directory.\n\nSEE ALSO\n       pushd(1), dirs(1)\n\nGNU bash                         March 2026                       POPD(1)",

    'dirs'      => "DIRS(1)                bash built-in                    DIRS(1)\n\nNAME\n       dirs - display directory stack\n\nSYNOPSIS\n       dirs [-clpv] [+N] [-N]\n\nDESCRIPTION\n       Display the list of currently remembered directories.\n       Directories are added to the list with the pushd command;\n       the popd command removes entries from the list.\n\n       -v     Print the directory stack with one entry per line,\n              prefixed by its index in the stack.\n\nEXAMPLES\n       dirs\n              Show the directory stack on one line.\n\n       dirs -v\n              Show numbered directory stack entries.\n\nSEE ALSO\n       pushd(1), popd(1)\n\nGNU bash                         March 2026                       DIRS(1)",

    'xargs'     => "XARGS(1)                  User Commands                  XARGS(1)\n\nNAME\n       xargs - build and execute command lines from standard input\n\nSYNOPSIS\n       xargs [OPTIONS] [COMMAND [INITIAL-ARGS]]\n\nDESCRIPTION\n       xargs reads items from standard input, delimited by whitespace\n       (or newlines), and executes COMMAND one or more times with any\n       INITIAL-ARGS followed by items read from standard input.\n\n       If no COMMAND is given, the default is echo.\n\nOPTIONS\n       -n MAX-ARGS\n              Use at most MAX-ARGS arguments per command line.\n\n       -I REPLACE-STR\n              Replace occurrences of REPLACE-STR in INITIAL-ARGS with\n              names read from standard input.\n\n       -d DELIM\n              Input items are terminated by DELIM instead of whitespace.\n\n       -0, --null\n              Input items are terminated by a null character instead of\n              whitespace (useful with find -print0).\n\n       -p, --interactive\n              Prompt before running each command line.\n\n       -t, --verbose\n              Print the command line before executing it.\n\nEXAMPLES\n       ls *.txt | xargs wc -l\n              Count lines in all .txt files.\n\n       find /etc -name '*.conf' | xargs grep 'localhost'\n              Search all .conf files for 'localhost'.\n\n       echo 'one two three' | xargs echo\n              Prints: one two three\n\n       echo 'a b c' | xargs -n 1 echo\n              Prints each word on its own line.\n\nSEE ALSO\n       find(1)\n\nGNU findutils                    March 2026                      XARGS(1)",

    'strace'    => "STRACE(1)                 User Commands                  STRACE(1)\n\nNAME\n       strace - trace system calls and signals\n\nSYNOPSIS\n       strace [-p PID] [-e trace=SYSCALLS] [COMMAND [ARGS]]\n\nDESCRIPTION\n       strace intercepts and records the system calls which are called\n       by a process and the signals which are received by a process.\n       The name of each system call, its arguments, and its return value\n       are printed on standard error or to the file specified with -o.\n\nOPTIONS\n       -p PID\n              Attach to the process with the process ID PID and begin\n              tracing.  Tracing may be stopped by pressing Ctrl+C.\n\n       -e trace=SET\n              Filter the set of syscalls traced. SET may be:\n              all         trace all syscalls (default)\n              file        trace file-related syscalls\n              network     trace network-related syscalls\n              process     trace process management syscalls\n\n       -o FILENAME\n              Write the trace output to the file FILENAME rather than\n              to standard error.\n\n       -s STRSIZE\n              Specify the maximum string size to print (default 32).\n\n       -f     Trace child processes as they are created.\n\n       -t     Prefix each line with the time of day.\n\n       -T     Show the time spent in each system call.\n\n       -c     Count time, calls, and errors for each syscall and report\n              a summary on program exit.\n\nEXAMPLES\n       strace ls\n              Trace the ls command.\n\n       strace -p 1234\n              Attach to process 1234 and trace its syscalls.\n\n       strace -e trace=network curl google.com\n              Trace only network syscalls made by curl.\n\n       strace -c ls\n              Summarise syscall counts for ls.\n\nAUTHOR\n       Written by Paul Kranenburg, Branko Lankester, and others.\n\nstrace                           March 2026                      STRACE(1)",

    'scp'       => "SCP(1)                    User Commands                    SCP(1)\n\nNAME\n       scp - OpenSSH secure file copy\n\nSYNOPSIS\n       scp [-346BCpqrTv] [-c cipher] [-F ssh_config] [-i identity_file]\n           [-J destination] [-l limit] [-o ssh_option] [-P port]\n           [-S program] source ... target\n\nDESCRIPTION\n       scp copies files between hosts on a network. It uses SSH for data\n       transfer and uses the same authentication and provides the same\n       security as SSH.\n\n       source and target may be specified as [user@]host:[path].\n\nOPTIONS\n       -P port\n              Specifies the port to connect to on the remote host.\n\n       -r, --recursive\n              Recursively copy entire directories.\n\n       -p     Preserves modification times, access times, and modes\n              from the original file.\n\n       -q     Quiet mode: disables the progress meter.\n\n       -v     Verbose mode: causes scp and ssh to print debugging messages\n              about their progress.\n\n       -i identity_file\n              Selects the file from which the identity (private key) for\n              public key authentication is read.\n\n       -C     Enable compression.\n\n       -3     Copies between two remote hosts are transferred through the\n              local host.\n\nEXAMPLES\n       scp file.txt user@192.168.1.20:/home/user/\n              Copy file.txt to the remote host.\n\n       scp -r /local/dir user@server:/remote/dir\n              Copy a directory recursively to a remote server.\n\n       scp user@server:/remote/file.txt /local/\n              Download a file from a remote host.\n\n       scp -P 2222 file.txt user@server:/tmp/\n              Use a non-standard SSH port.\n\nSEE ALSO\n       ssh(1), sftp(1)\n\nOpenSSH                          March 2026                         SCP(1)",

    'nmcli'     => "NMCLI(1)                  User Commands                  NMCLI(1)\n\nNAME\n       nmcli - command-line tool for controlling NetworkManager\n\nSYNOPSIS\n       nmcli [OPTIONS] OBJECT { COMMAND | help }\n\nDESCRIPTION\n       nmcli is a command-line client for NetworkManager. It allows\n       controlling NetworkManager and reporting its status.\n\nOBJECTS\n       general [status]\n              Show overall status of NetworkManager.\n\n       device [status]\n              List managed devices and their state.\n\n       device show [IFACE]\n              Show detailed info about a specific device.\n\n       connection [show]\n              List saved network connections.\n\n       connection show [NAME]\n              Show details of a specific connection.\n\n       radio   Show or change radio switches (WiFi, WWAN).\n\nOPTIONS\n       -v, --version\n              Show program version.\n\n       -h, --help\n              Print help.\n\nEXAMPLES\n       nmcli device status\n              Show status of all network devices.\n\n       nmcli connection show\n              List all network connections.\n\n       nmcli device show eth0\n              Show detailed information about eth0.\n\n       nmcli general status\n              Show overall NetworkManager connectivity status.\n\nFILES\n       /etc/NetworkManager/NetworkManager.conf\n              Main configuration file.\n       /etc/NetworkManager/system-connections/\n              Stored connection profiles.\n\nSEE ALSO\n       NetworkManager(8)\n\nNetworkManager                   March 2026                      NMCLI(1)",
];
